85	          placeholder="例如：我需要一台用于日常开发的高性能笔记本电脑"
86	          rows={3}
87	          className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
88	        />
89	        <Button onClick={handleRecommend} disabled={recommending || !requirement.trim()}>
90	          {recommending ? "推荐中..." : "获取推荐"}
91	        </Button>
92	        {recommendError && (
93	          <p className="text-sm text-destructive">{recommendError}</p>
94	        )}
95	        {recommendations.length > 0 && (
96	          <div className="space-y-2 mt-2">
97	            <p className="text-sm font-medium">推荐结果：</p>
98	            {recommendations.map((r) => (
99	              <label
100	                key={r.modelId}
101	                className={`flex items-start gap-3 rounded-lg border p-3 cursor-pointer transition-colors ${
102	                  selectedModelId === r.modelId ? "border-primary bg-primary/5" : ""
103	                }`}
104	              >
105	                <input
106	                  type="radio"
107	                  name="model"
108	                  value={r.modelId}
109	                  checked={selectedModelId === r.modelId}
110	                  onChange={() => setSelectedModelId(r.modelId)}
111	                  className="mt-1"
112	                />
113	                <div className="flex-1">
114	                  <div className="flex items-center justify-between">
115	                    <span className="font-medium text-sm">型号 ID: {r.modelId}</span>
116	                    <span className="text-sm font-bold text-primary">{r.score}分</span>
117	                  </div>
118	                  <p className="text-sm text-muted-foreground mt-1">{r.reason}</p>
119	                </div>
120	              </label>
121	            ))}
122	          </div>
123	        )}
124	      </div>
125	
126	      {/* Submit Form */}
127	      <div className="rounded-lg border p-4 space-y-3">
128	        <h2 className="font-semibold">提交申请</h2>
129	        <div className="space-y-2">
130	          <label className="text-sm font-medium">选择设备</label>
131	          {recommendations.length === 0 ? (
132	            <div className="space-y-1">
133	              <p className="text-xs text-muted-foreground">
134	                请先使用 AI 推荐获取设备型号，或直接输入型号 ID
135	              </p>
136	              <input
137	                value={selectedModelId}
138	                onChange={(e) => setSelectedModelId(e.target.value)}
139	                placeholder="输入型号 ID"
140	                className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
141	              />
142	            </div>
143	          ) : (
144	            <p className="text-sm text-muted-foreground">
145	              已选择推荐列表中的设备
146	            </p>
147	          )}
148	        </div>
149	        <div className="space-y-2">
150	          <label className="text-sm font-medium">申请理由</label>
151	          <textarea
152	            value={reason}
153	            onChange={(e) => setReason(e.target.value)}
154	            placeholder="请说明申请理由..."
155	            rows={3}
156	            className="w-full rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50"
157	          />
158	        </div>
159	        {submitError && (
160	          <p className="text-sm text-destructive">{submitError}</p>
161	        )}
162	        <Button onClick={handleSubmit} disabled={submitting || !selectedModelId || !reason.trim()}>
163	          {submitting ? "提交中..." : "提交申请"}
164	        </Button>
165	      </div>
166	    </div>
167	  );
168	}
